// 1. Get the raw text string from the AI Agent output
let rawText = $json.output || "";

// 2. Clean out the ```json and ``` markdown backticks
let cleanText = rawText.replace(/^```json\s*/i, "").replace(/\s*```$/, "").trim();

// 3. Parse the clean string into real JSON
const parsedOutput = JSON.parse(cleanText);

// 4. Return ONLY the token_usage object
return {
  token_usage: parsedOutput.token_usage
};

